// --- Secure message protocol using sealed trait + safe serialization ---

sealed trait AppMessage extends Serializable
final case class TextMessage(sender: String, content: String) extends AppMessage
final case class PingMessage(timestamp: Long) extends AppMessage
final case class PongMessage(timestamp: Long) extends AppMessage

// --- Safe deserializer with strict allowlist ---

class SafeObjectInputStream(in: ByteArrayInputStream) extends ObjectInputStream(in) {

  // STRICT ALLOWLIST: Only these classes may be deserialized
  private val allowedClasses: Set[String] = Set(
    classOf[TextMessage].getName,
    classOf[PingMessage].getName,
    classOf[PongMessage].getName,
    "scala.collection.immutable.List",
    "java.lang.String",
    "java.lang.Long",
    "java.lang.Number"
  )

  override def resolveClass(desc: ObjectStreamClass): Class[_] = {
    val className = desc.getName
    if (!allowedClasses.contains(className) && !className.startsWith("[") /* arrays */) {
      throw new SecurityException(
        s"Deserialization of class '$className' is not allowed. " +
        s"Only allowlisted message types are permitted."
      )
    }
    super.resolveClass(desc)
  }
}

// --- Message serialization helper ---

object SecureMessageSerializer {

  def serialize(msg: AppMessage): Array[Byte] = {
    val baos = new ByteArrayOutputStream()
    val oos = new ObjectOutputStream(baos)
    try {
      oos.writeObject(msg)
      oos.flush()
      baos.toByteArray
    } finally {
      oos.close()
      baos.close()
    }
  }

  def deserialize(data: Array[Byte]): Either[String, AppMessage] = {
    if (data.length > 10 * 1024) {
      return Left("Message too large: exceeds 10KB limit")
    }

    val bais = new ByteArrayInputStream(data)
    try {
      val ois = new SafeObjectInputStream(bais)
      try {
        ois.readObject() match {
          case msg: AppMessage => Right(msg)
          case other =>
            Left(s"Unexpected object type: ${other.getClass.getName}")
        }
      } finally {
        ois.close()
      }
    } catch {
      case se: SecurityException =>
        Left(s"Security violation: ${se.getMessage}")
      case e: Exception =>
        Left(s"Deserialization error: ${e.getMessage}")
    }
  }
}

// --- Message processing actor ---

class MessageProcessorActor extends Actor with ActorLogging {
  override def receive: Receive = {
    case msg: TextMessage =>
      log.info(s"Received text from '${msg.sender}': ${msg.content}")
      sender() ! PongMessage(System.currentTimeMillis())

    case msg: PingMessage =>
      log.info(s"Received ping at ${msg.timestamp}")
      sender() ! PongMessage(System.currentTimeMillis())

    case msg: PongMessage =>
      log.info(s"Received pong at ${msg.timestamp}")
  }
}

// --- TCP connection handler actor ---

class ConnectionHandlerActor(processor: ActorRef) extends Actor with ActorLogging {
  import Tcp._

  private var buffer: ByteString = ByteString.empty
  private val LengthHeaderSize = 4

  override def receive: Receive = {
    case Received(data) =>
      buffer ++= data
      processBuffer()

    case PeerClosed =>
      log.info("Peer closed connection")
      context.stop(self)

    case ErrorClosed(cause) =>
      log.warning(s"Connection error: $cause")
      context.stop(self)
  }

  private def processBuffer(): Unit = {
    while (buffer.length >= LengthHeaderSize) {
      val msgLength = buffer.iterator.getInt
      if (msgLength <= 0 || msgLength > 10 * 1024) {
        log.warning(s"Invalid message length: $msgLength. Closing connection.")
        sender() ! Tcp.Close
        return
      }
      if (buffer.length >= LengthHeaderSize + msgLength) {
        val msgBytes = buffer.slice(LengthHeaderSize, LengthHeaderSize + msgLength).toArray
        buffer = buffer.drop(LengthHeaderSize + msgLength)

        SecureMessageSerializer.deserialize(msgBytes) match {
          case Right(msg) =>
            log.info(s"Successfully deserialized: ${msg.getClass.getSimpleName}")
            processor ! msg
          case Left(error) =>
            log.warning(s"Rejected message: $error")
        }
      } else {
        return // Wait for more data
      }
    }
  }
}

// --- TCP server actor ---

class TcpServerActor(host: String, port: Int, processor: ActorRef) extends Actor with ActorLogging {
  import Tcp._
  import context.system

  IO(Tcp) ! Bind(self, new InetSocketAddress(host, port))

  override def receive: Receive = {
    case Bound(localAddress) =>
      log.info(s"Server bound to $localAddress")

    case CommandFailed(_: Bind) =>
      log.error(s"Failed to bind to $host:$port")
      context.stop(self)

    case Connected(remote, _) =>
      log.info(s"New connection from $remote")
      val handler = context.actorOf(Props(new ConnectionHandlerActor(processor)))
      sender() ! Register(handler)
  }
}

